import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handling user input by encoding it to prevent XSS
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");

        try {
            out.println("<p>User input: " + ESAPI.encoder().encodeForHTML(userInput) + "</p>"); // Safe from XSS
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
        }

        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
